import { useEffect, useState, useMemo } from "react";
import { db } from "../firebase";
import { doc, onSnapshot } from "firebase/firestore";
import { speakTactical } from "../utils/tts";

/**
 * SENTINEL Phase 3 — Production AI SitRep Panel
 * Listen to /sessions/current for the Gemini-generated Situation Report.
 * This report is generated by the Cloud Function (backend/cloud-functions/gemini-trigger).
 */
export default function SitRepPanel({ focusedIncident }) {
  const [sitrep, setSitrep] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  // Trigger Logic: FCM triggers are now handled inside the Firestore listener
  // to ensure one-way data flow and prevent redundant local fetches during demos.

  useEffect(() => {
    // Listen to the session document written by the Gemini Cloud Function
    const unsub = onSnapshot(doc(db, "sessions", "current"), (snap) => {
      setLoading(false);
      if (snap.exists()) {
        const data = snap.data();
        if (data.sitrep_error) {
          setError(data.sitrep_error);
          setSitrep(null);
        } else if (data.current_sitrep) {
          // 🛡️ Phase 4 Integration: Auto-dispatch to FCM only if in production
          const current = data.current_sitrep;
          setSitrep(current);
          setError(null);

          if (current.severity === "P0") {
            const baseUrl = import.meta.env.VITE_EVENT_PROCESSOR_URL || "https://sentinel-processor-final.onrender.com";
            
            // 📡 P0 Mass Notification Dispatch (Phase 4 Logic)
            fetch(`${baseUrl}/dispatch-fcm`, {
              method: "POST",
              headers: { "Content-Type": "application/json" },
              body: JSON.stringify(current)
            }).then(res => {
              if (res.status === 404) {
                console.warn("🛡️ [Phase 4] Notification Dispatcher endpoint not yet deployed to backend.");
              } else if (res.ok) {
                console.log("🚀 [Phase 4] P0 Emergency Notifications sent via GCP/Render.");
              }
            }).catch(() => {
              // Network level catch (Service down or CORS)
              console.log("ℹ️ [Phase 4] Notification Dispatch skipped. (Check VITE_EVENT_PROCESSOR_URL)");
            });
          }
        }
      } else {
        setSitrep(null);
        setError("Session data not found.");
      }
    }, (err) => {
      console.error("Firestore SitRep error:", err);
      setError("Failed to sync with SENTINEL AI.");
      setLoading(false);
    });

    return () => unsub();
  }, []);

  const effectiveSitRep = useMemo(() => {
    if (focusedIncident) {
      const type = focusedIncident.event_type;
      const nodeId = focusedIncident.location?.nodeId || "UNKNOWN";
      
      const procedures = {
        FIRE: ["EVACUATE IMMEDIATELY", "SEAL FIRE DOORS", "ACTIVATE SPRINKLERS", "DISPATCH EMERGENCY RESPONSE"],
        SMOKE: ["WEAR PROTECTIVE MASKS", "REDUCE VENTILATION", "INVESTIGATE SOURCE", "EVACUATE ADJACENT FLOORS"],
        TRAPPED: ["INITIATE SEARCH AND RESCUE", "MAINTAIN COMMUNICATIONS", "DEPLOY LIFTING EQUIPMENT", "CLEAR ACCESS PATHS"],
        MEDICAL: ["DISPATCH MEDICAL TEAM", "CLEAR AMBULANCE BAY", "PREPARE TRIAGE ZONE", "SECURE AREA FOR PRIVACY"],
        INJURY: ["PROVIDE FIRST AID", "ASSESS SEVERITY", "REQUEST TRANSPORT", "STABILIZE PATIENT"],
        PANIC: ["RESTORE ORDER", "USE CALMING ANNOUNCEMENTS", "SECURE EXITS", "MONITOR CROWD FLOW"],
        MASS_CASUALTY: ["ACTIVATE MCI PROTOCOL", "ESTABLISH FIELD HOSPITAL", "REQUEST EXTERNAL AID", "TRIAGE ALL VICTIMS"]
      };

      return {
        severity: focusedIncident.confidence > 0.9 ? "P0" : "P1",
        threat_summary: `${type} EMERGENCY DETECTED AT NODE::${nodeId}`,
        safe_exits: ["ALL OTHER SECTORS NOMINAL"],
        blocked_exits: [nodeId],
        recommended_actions: procedures[type] || ["INVESTIGATE IMMEDIATELY", "MONITOR SYSTEM STATUS"],
        isFocused: true
      };
    }
    return sitrep;
  }, [sitrep, focusedIncident]);

  const handleSpeak = () => {
    if (!effectiveSitRep) return;
    
    let text = "";
    if (focusedIncident) {
      const type = focusedIncident.event_type;
      const loc  = focusedIncident.location?.zone || "Current Location";
      
      const templates = {
        FIRE: `Emergency. Fire detected in ${loc}. Evacuate immediately via designated safe paths. Do not use elevators.`,
        SMOKE: `Smoke reported in ${loc}. Protective masks required for entry. Reduce ventilation in the area.`,
        TRAPPED: `Search and rescue required in ${loc}. High priority victims reported. Dispatching specialized units.`,
        MEDICAL: `Medical emergency confirmed in ${loc}. Dispatching paramedics. Clear ambulance bay for arrival.`,
        INJURY: `Injury reported at ${loc}. First aid team dispatched for assessment and stabilization.`,
        PANIC: `Panic alert at ${loc}. Maintain calm. Use authorized exit routes only. Security is responding.`,
        MASS_CASUALTY: `Critical. Mass casualty event confirmed at ${loc}. Triage protocol alpha is now active.`
      };
      
      text = templates[type] || `Emergency alert at ${loc}. Follow standard procedure for ${type}.`;
    } else {
      text = `Severity ${effectiveSitRep.severity}. ${effectiveSitRep.threat_summary}. Recommended actions: ${effectiveSitRep.recommended_actions?.join(", ")}`;
    }

    speakTactical(text);
  };

  if (loading) return (
    <div style={{ padding: "1.5rem", textAlign: "center", color: "var(--accent-color, #6366f1)" }}>
      <div className="pulse" style={{ fontWeight: 800 }}>🤖 Syncing with Root AI Agent...</div>
    </div>
  );

  if (error) return (
    <div style={{ padding: "1.2rem", color: "#ef4444", border: "1px solid #ef444433", borderRadius: "10px", background: "rgba(239, 68, 68, 0.05)" }}>
      <strong>⚠️ AI Sync Error:</strong> {error}
    </div>
  );

  if (!effectiveSitRep) return (
    <div style={{ padding: "1.2rem", opacity: 0.5, textAlign: "center", border: "1px dashed rgba(255,255,255,0.1)", borderRadius: "10px" }}>
      System Nominal. All hospital zones monitored. Awaiting first incident analysis.
    </div>
  );

  const color = effectiveSitRep?.severity === "P0" ? "var(--accent)" : "var(--neon-orange)";

  return (
    <div className="animate-in" style={{ 
      fontFamily: "JetBrains Mono",
      color: "var(--text-main)",
      fontSize: "0.7rem"
    }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "1.25rem", borderBottom: `1px solid ${color}33`, paddingBottom: "0.5rem" }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
          <div style={{ width: '6px', height: '6px', background: color, boxShadow: `0 0 8px ${color}` }} />
          <span style={{ fontWeight: 700, color }}>{effectiveSitRep.isFocused ? "FOCUS::" : "LVL::"}{effectiveSitRep.severity}</span>
        </div>
        <button
          onClick={handleSpeak}
          className="btn"
          style={{ padding: "2px 8px", fontSize: "0.5rem", height: 'auto' }}
        >VOICE_LINK</button>
      </div>

      <div style={{ marginBottom: "1.5rem", opacity: 0.9, lineHeight: 1.5, letterSpacing: '0.05em' }}>
        {effectiveSitRep.threat_summary?.toUpperCase()}
      </div>

      <div style={{ display: "flex", flexDirection: 'column', gap: "8px", marginBottom: "1.5rem" }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', borderBottom: '1px solid var(--border-dim)', paddingBottom: '4px' }}>
          <span style={{ color: 'var(--text-muted)' }}>SECTORS_SAFE:</span>
          <span style={{ color: "var(--neon-green)" }}>{effectiveSitRep.safe_exits?.join(" | ") || "SEARCHING"}</span>
        </div>
        <div style={{ display: 'flex', justifyContent: 'space-between', borderBottom: '1px solid var(--border-dim)', paddingBottom: '4px' }}>
          <span style={{ color: 'var(--text-muted)' }}>SECTORS_BLOCKED:</span>
          <span style={{ color: "var(--accent)" }}>{effectiveSitRep.blocked_exits?.join(" | ") || "NONE"}</span>
        </div>
      </div>

      {effectiveSitRep.recommended_actions?.length > 0 && (
        <div>
          <div style={{ color: "var(--primary)", fontWeight: 700, marginBottom: "8px", fontSize: '0.6rem' }}>// RECOMMENDED_PROCEDURES</div>
          <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
            {effectiveSitRep.recommended_actions.map((action, i) => (
              <div key={i} style={{ display: 'flex', gap: '8px', opacity: 0.7 }}>
                <span>0{i+1}_</span>
                <span>{action.toUpperCase()}</span>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}
